   556	- (NSMutableDictionary *)stateForPath:(NSString *)path createIfNeeded:(BOOL)create {
   557	    if (path.length == 0) return nil;
   558	    NSMutableDictionary *state = self.resCleanupStates[path];
   559	    if (!state && create) {
   560	        state = [@{ @"unzipDone": @NO, @"sha1Done": @NO, @"cleanupRequested": @NO } mutableCopy];
   561	        self.resCleanupStates[path] = state;
   562	    }
   563	    return state;
   564	}
