   566	- (void)markResUnzipCompletedAtPath:(NSString *)path {
   567	    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
   568	    if (!state) return;
   569	    state[@"unzipDone"] = @YES;
   570	    [self tryPerformResCleanupAtPath:path];
   571	}
   572	
   573	- (void)markResSHA1CompletedAtPath:(NSString *)path {
   574	    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
