   579	
   580	- (void)requestResCleanupAtPath:(NSString *)path {
   581	    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
   582	    if (!state) return;
   583	    state[@"cleanupRequested"] = @YES;
   584	}
   585	
   586	- (void)tryPerformResCleanupAtPath:(NSString *)path {
   587	    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:NO];
   588	    if (!state) return;
   589	    BOOL cleanupRequested = [state[@"cleanupRequested"] boolValue];
   590	    BOOL unzipDone = [state[@"unzipDone"] boolValue];
   591	    BOOL sha1Done = [state[@"sha1Done"] boolValue];
   592	    if (cleanupRequested && unzipDone && sha1Done) {
   593	        NSFileManager *fileManager = [NSFileManager defaultManager];
   594	        NSError *error = nil;
   595	        if ([fileManager fileExistsAtPath:path]) {
   596	            [fileManager removeItemAtPath:path error:&error];
   597	        }
   598	        [self.resCleanupStates removeObjectForKey:path];
   599	    }
   600	}
