   672	- (void)saveRouteLogFile:(NSDictionary *)routeLog {
   673	    if (!routeLog || routeLog.count == 0) {
   674	        return;
   675	    }
   676	    
   677	    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
   678	        NSMutableArray<NSDictionary *> *existingLogs = [[self loadRouteLogFile] mutableCopy];
   679	        [existingLogs addObject:routeLog];  // 添加新日志
   680	        
   681	        // 限制日志数量，避免文件过大（保留最近1000条）
   682	        const NSUInteger maxLogCount = 1000;
   683	        if (existingLogs.count > maxLogCount) {
   684	            NSRange rangeToKeep = NSMakeRange(existingLogs.count - maxLogCount, maxLogCount);
   685	            existingLogs = [[existingLogs subarrayWithRange:rangeToKeep] mutableCopy];
   686	        }
   687	        
   688	        NSError *error = nil;
   689	        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:existingLogs options:0 error:&error];
